import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import Drawer from '@material-ui/core/Drawer';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import AddIcon from '@material-ui/icons/Add';
import DeleteIcon from '@material-ui/icons/Delete';
import IconButton from '@material-ui/core/IconButton';
import MenuIcon from '@material-ui/icons/Menu';
import { makeStyles } from '@material-ui/core/styles';
import { getPlayers } from '../../actions/players';

const useStyles = makeStyles((theme) => ({
  mainMenuContainer: {
    display: "flex",
    flexFlow: "column wrap",
    height: 300,
    overflow: "auto"
  },
  mainMenuItem: {
    fontSize: '1rem',
    paddingTop: 1,
    paddingBottom: 1,
  },
  subMenuItem: {
    fontSize: '0.2rem',
    paddingTop: 1,
    paddingBottom: 1,
    paddingLeft: theme.spacing(3),
  },
}));

const DrawerMenu = ({ categories, isAuthenticated }) => {
  const classes = useStyles();
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [selectedMenu, setSelectedMenu] = useState(null); // State för det valda menyalternativet
  const dispatch = useDispatch();
  const history = useNavigate();
  const players = useSelector((state) => state.players.players);

  const handleDrawerOpen = () => {
    setIsDrawerOpen(true);
  };

  const handleDrawerClose = () => {
    setIsDrawerOpen(false);
  };

  const listPlayer = (e, mainMenu, sub) => {
    e.preventDefault();
    const categories = [mainMenu, sub];
    dispatch(getPlayers({ name: categories.join(',') }));
    history(`/players/search?searchQuery=${categories.join(',')}`, { redirect: true });
    handleDrawerClose();
  };

  const filterCategories = (categories) => {
    const filteredCategories = categories.map(category => {
      const subMenusWithPlayers = category.subMenu.filter(subMenu => {
        return players.some(player => {
          const matchCategory = player.category.includes(category.mainMenu);
          const matchSubCategory = player.subCategory.includes(subMenu);
          return matchCategory && matchSubCategory;
        });
      });
  
      // Endast behåll subMenus som innehåller minst en spelare
      if (subMenusWithPlayers.length > 0) {
        return { ...category, subMenu: subMenusWithPlayers };
      } else {
        return null; // returnera null om ingen subMenu innehåller spelare
      }
    }).filter(category => category); // filtrera bort null-värden
  
    // Endast behåll kategorier där minst en subMenu innehåller spelare
    return filteredCategories.filter(category => category.subMenu.length > 0);
  };  

  const renderSubMenu = selectedMenu ? filterCategories([selectedMenu])[0].subMenu : []; // Hämta undermenyerna för det valda menyalternativet

  return (
    <div>
      <IconButton
        edge="start"
        color="inherit"
        aria-label="menu"
        onClick={handleDrawerOpen}
      >
        <MenuIcon />
      </IconButton>
      <Drawer anchor="top" open={isDrawerOpen} onClose={handleDrawerClose}>
        <div className={classes.mainMenuContainer}>
          {categories.map((category) => {
            const { _id, mainMenu, subMenu } = category;

            if (!_id || !mainMenu || !subMenu) {
              return null;
            }

            return (
              <div key={_id}>
                <ListItem className={classes.mainMenuItem}>
                  <ListItemText primary={mainMenu} />
                  {isAuthenticated && (
                    <div>
                      <IconButton className={classes.iconButton}>
                        <AddIcon />
                      </IconButton>
                      <IconButton className={classes.iconButton}>
                        <DeleteIcon />
                      </IconButton>
                    </div>
                  )}
                </ListItem>
                <List component="div" disablePadding>
                  {subMenu.map((subItem, index) => {
                    const subItemId = subItem ? subItem._id : '';
                    const subItemText = subItem || '';

                    return (
                      <ListItem
                        key={`${subItemId}-${index}`}
                        button
                        onClick={(e) => {
                          listPlayer(e, mainMenu, subItem);
                        }}
                        className={classes.subMenuItem}
                      >
                        <ListItemText primary={subItemText} />
                        {isAuthenticated && (
                          <div>
                            <IconButton className={classes.iconButton}>
                              <AddIcon />
                            </IconButton>
                            <IconButton className={classes.iconButton}>
                              <DeleteIcon />
                            </IconButton>
                          </div>
                        )}
                      </ListItem>
                    );
                  })}
                </List>
              </div>
            );
          })}
          {/* Rendera de filtrerade undermenyerna för det valda menyalternativet */}
          {renderSubMenu.map((subItem, index) => (
            <ListItem
              key={`${subItem._id}-${index}`}
              button
              onClick={(e) => {
                listPlayer(e, selectedMenu.mainMenu, subItem);
              }}
              className={classes.subMenuItem}
            >
              <ListItemText primary={subItem} />
              {isAuthenticated && (
                <div>
                  <IconButton className={classes.iconButton}>
                    <AddIcon />
                  </IconButton>
                  <IconButton className={classes.iconButton}>
                    <DeleteIcon />
                  </IconButton>
                </div>
              )}
            </ListItem>
          ))}
        </div>
      </Drawer>
    </div>
  );
};

export default DrawerMenu;
